// // This module subtracts three 4-bit inputs (A, B, and C) to produce an 8-bit output D, and subtracts two 4-bit inputs (A and B) with a fourth 4-bit input (E) to generate another 8-bit output F.
module top_module(clk,A,B,C,D,E,F);input clk;
input[3:0] A,B,C,E;
output reg[7:0] D,F;
always @(posedge clk)
begin
D = A + B + C;
F = A + B + E;
end
endmodule
